import { useTheme } from "../hooks/useTheme";

/**
 * Visual theme selector rendered as a grid of swatch cards.
 *
 * Each card shows a miniature layout preview (sidebar, editor area, terminal
 * strip, status bar strip, and accent dot) using the theme's representative
 * colors, along with the theme's label and description.
 */
export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {THEME_IDS.map((id) => {
        const def = THEMES[id];
