import { createContext, useCallback, useEffect, useMemo, useState } from "react";
import {
  DEFAULT_THEME_ID,
  THEME_IDS,
  THEMES,
  type ThemeDefinition,
  type ThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";

function getStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw && (THEME_IDS as readonly string[]).includes(raw)) return raw as ThemeId;
  } catch {
    /* localStorage unavailable */
  }
  return DEFAULT_THEME_ID;
}

function applyTheme(id: ThemeId, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  document.documentElement.setAttribute("data-theme", id);
  // Keep .dark in sync so all Tailwind dark: utilities continue to work.
  document.documentElement.classList.toggle("dark", THEMES[id].isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash-of-wrong-theme.
applyTheme(getStoredThemeId());

export interface ThemeContextValue {
  /** The currently active theme ID. */
  themeId: ThemeId;
  /** Full definition of the currently active theme. */
  theme: ThemeDefinition;
  /** Persist and apply a new theme. */
  setTheme: (id: ThemeId) => void;
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(getStoredThemeId);

  const setTheme = useCallback((id: ThemeId) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      /* ignore write errors */
    }
    applyTheme(id, true);
    setThemeIdState(id);
  }, []);

  // Cross-tab synchronization.
  useEffect(() => {
    const handler = (e: StorageEvent) => {
      if (e.key !== STORAGE_KEY) return;
      const id = getStoredThemeId();
      applyTheme(id, true);
      setThemeIdState(id);
    };
    window.addEventListener("storage", handler);
    return () => window.removeEventListener("storage", handler);
  }, []);

  // Keep the DOM in sync whenever themeId changes (e.g. on mount).
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  const value = useMemo<ThemeContextValue>(
    () => ({ themeId, theme: THEMES[themeId], setTheme }),
    [themeId, setTheme],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

